6: import * as vscode from 'vscode';
7: import { TypeScriptServiceConfiguration } from '../configuration/configuration';
8: import { DiagnosticLanguage } from '../configuration/languageDescription';
9: import { TelemetryReporter } from '../logging/telemetry';
10: import { DiagnosticPerformanceData as TsDiagnosticPerformanceData } from '../tsServer/protocol/protocol';
11: import * as arrays from '../utils/arrays';
12: import { Disposable } from '../utils/dispose';
13: import { equals } from '../utils/objects';
14: import { ResourceMap } from '../utils/resourceMap';
15: 
16: function diagnosticsEquals(a: vscode.Diagnostic, b: vscode.Diagnostic): boolean {
17: 	if (a === b) {
18: 		return true;
19: 	}
20: 
21: 	return a.code === b.code
22: 		&& a.message === b.message
23: 		&& a.severity === b.severity
24: 		&& a.source === b.source
25: 		&& a.range.isEqual(b.range)
26: 		&& arrays.equals(a.relatedInformation || arrays.empty, b.relatedInformation || arrays.empty, (a, b) => {
27: 			return a.message === b.message
28: 				&& a.location.range.isEqual(b.location.range)
29: 				&& a.location.uri.fsPath === b.location.uri.fsPath;
30: 		})
31: 		&& arrays.equals(a.tags || arrays.empty, b.tags || arrays.empty);
32: }
33: 
34: export const enum DiagnosticKind {
35: 	Syntax,
36: 	Semantic,
37: 	Suggestion,
38: 	RegionSemantic,
39: }
40: 
41: class FileDiagnostics {
42: 
43: 	private readonly _diagnostics = new Map<DiagnosticKind, ReadonlyArray<vscode.Diagnostic>>();
44: 
45: 	constructor(
46: 		public readonly file: vscode.Uri,
47: 		public language: DiagnosticLanguage
48: 	) { }
49: 
50: 	public updateDiagnostics(
51: 		language: DiagnosticLanguage,
52: 		kind: DiagnosticKind,
53: 		diagnostics: ReadonlyArray<vscode.Diagnostic>,
54: 		ranges: ReadonlyArray<vscode.Range> | undefined
55: 	): boolean {
56: 		if (language !== this.language) {
57: 			this._diagnostics.clear();
58: 			this.language = language;
59: 		}
60: 
61: 		const existing = this._diagnostics.get(kind);
62: 		if (existing?.length === 0 && diagnostics.length === 0) {
63: 			// No need to update
64: 			return false;
65: 		}
66: 
67: 		if (kind === DiagnosticKind.RegionSemantic) {
68: 			return this.updateRegionDiagnostics(diagnostics, ranges!);
69: 		}
70: 		this._diagnostics.set(kind, diagnostics);
71: 		return true;
72: 	}
73: 
74: 	public getAllDiagnostics(settings: DiagnosticSettings): vscode.Diagnostic[] {
75: 		if (!settings.getValidate(this.language)) {
76: 			return [];
77: 		}
78: 
79: 		return [
80: 			...this.get(DiagnosticKind.Syntax),
81: 			...this.get(DiagnosticKind.Semantic),
82: 			...this.getSuggestionDiagnostics(settings),
83: 		];
84: 	}
85: 
86: 	public delete(toDelete: vscode.Diagnostic): void {
87: 		for (const [type, diags] of this._diagnostics) {
88: 			this._diagnostics.set(type, diags.filter(diag => !diagnosticsEquals(diag, toDelete)));
89: 		}
90: 	}
91: 
92: 	/**
93: 	 * @param ranges The ranges whose diagnostics were updated.
94: 	 */
95: 	private updateRegionDiagnostics(
96: 		diagnostics: ReadonlyArray<vscode.Diagnostic>,
97: 		ranges: ReadonlyArray<vscode.Range>): boolean {
98: 		if (!this._diagnostics.get(DiagnosticKind.Semantic)) {
99: 			this._diagnostics.set(DiagnosticKind.Semantic, diagnostics);
100: 			return true;
101: 		}
102: 		const oldDiagnostics = this._diagnostics.get(DiagnosticKind.Semantic)!;
103: 		const newDiagnostics = oldDiagnostics.filter(diag => !ranges.some(range => diag.range.intersection(range)));
104: 		newDiagnostics.push(...diagnostics);
105: 		this._diagnostics.set(DiagnosticKind.Semantic, newDiagnostics);
106: 		return true;
107: 	}
108: 
109: 	private getSuggestionDiagnostics(settings: DiagnosticSettings) {
110: 		const enableSuggestions = settings.getEnableSuggestions(this.language);
111: 		return this.get(DiagnosticKind.Suggestion).filter(x => {
112: 			if (!enableSuggestions) {
113: 				// Still show unused
114: 				return x.tags && (x.tags.includes(vscode.DiagnosticTag.Unnecessary) || x.tags.includes(vscode.DiagnosticTag.Deprecated));
115: 			}
116: 			return true;
117: 		});
118: 	}
119: 
120: 	private get(kind: DiagnosticKind): ReadonlyArray<vscode.Diagnostic> {
121: 		return this._diagnostics.get(kind) || [];
122: 	}
123: }
