125: interface LanguageDiagnosticSettings {
126: 	readonly validate: boolean;
127: 	readonly enableSuggestions: boolean;
128: }
129: 
130: function areLanguageDiagnosticSettingsEqual(currentSettings: LanguageDiagnosticSettings, newSettings: LanguageDiagnosticSettings): boolean {
131: 	return currentSettings.validate === newSettings.validate
132: 		&& currentSettings.enableSuggestions === newSettings.enableSuggestions;
133: }
134: 
135: class DiagnosticSettings {
136: 	private static readonly defaultSettings: LanguageDiagnosticSettings = {
137: 		validate: true,
138: 		enableSuggestions: true
139: 	};
140: 
141: 	private readonly _languageSettings = new Map<DiagnosticLanguage, LanguageDiagnosticSettings>();
142: 
143: 	public getValidate(language: DiagnosticLanguage): boolean {
144: 		return this.get(language).validate;
145: 	}
146: 
147: 	public setValidate(language: DiagnosticLanguage, value: boolean): boolean {
148: 		return this.update(language, settings => ({
149: 			validate: value,
150: 			enableSuggestions: settings.enableSuggestions,
151: 		}));
152: 	}
153: 
154: 	public getEnableSuggestions(language: DiagnosticLanguage): boolean {
155: 		return this.get(language).enableSuggestions;
156: 	}
157: 
158: 	public setEnableSuggestions(language: DiagnosticLanguage, value: boolean): boolean {
159: 		return this.update(language, settings => ({
160: 			validate: settings.validate,
161: 			enableSuggestions: value
162: 		}));
163: 	}
164: 
165: 	private get(language: DiagnosticLanguage): LanguageDiagnosticSettings {
166: 		return this._languageSettings.get(language) || DiagnosticSettings.defaultSettings;
167: 	}
168: 
169: 	private update(language: DiagnosticLanguage, f: (x: LanguageDiagnosticSettings) => LanguageDiagnosticSettings): boolean {
170: 		const currentSettings = this.get(language);
171: 		const newSettings = f(currentSettings);
172: 		this._languageSettings.set(language, newSettings);
173: 		return !areLanguageDiagnosticSettingsEqual(currentSettings, newSettings);
174: 	}
175: }
