91: 	public change(resource: vscode.Uri, filepath: string, events: readonly vscode.TextDocumentContentChangeEvent[]) {
92: 		if (!events.length) {
93: 			return;
94: 		}
95: 
96: 		this.updatePending(resource, new ChangeOperation({
97: 			fileName: filepath,
98: 			textChanges: events.map((change): Proto.CodeEdit => ({
99: 				newText: change.text,
100: 				start: typeConverters.Position.toLocation(change.range.start),
101: 				end: typeConverters.Position.toLocation(change.range.end),
102: 			})).reverse(), // Send the edits end-of-document to start-of-document order
103: 		}));
