617: 	public interruptGetErr<R>(f: () => R): R {
618: 		if (!this.pendingGetErr
619: 			|| this.client.configuration.enableProjectDiagnostics // `geterr` happens on separate server so no need to cancel it.
620: 		) {
621: 			return f();
622: 		}
623: 
624: 		this.pendingGetErr.cancel();
625: 		this.pendingGetErr = undefined;
626: 		const result = f();
627: 		this.triggerDiagnostics();
628: 		return result;
629: 	}
