    19→
    20→type ScriptKind = 'TS' | 'TSX' | 'JS' | 'JSX';
    21→
    22→function mode2ScriptKind(mode: string): ScriptKind | undefined {
    23→	switch (mode) {
    24→		case languageModeIds.typescript: return 'TS';
    25→		case languageModeIds.typescriptreact: return 'TSX';
    26→		case languageModeIds.javascript: return 'JS';
    27→		case languageModeIds.javascriptreact: return 'JSX';
    28→	}
    29→	return undefined;
    30→}
    31→
    32→const enum BufferState { Initial, Open, Closed }
    33→
    34→const enum BufferOperationType { Close, Open, Change }
    35→
    36→class CloseOperation {
    37→	readonly type = BufferOperationType.Close;
    38→	constructor(
    39→		public readonly args: string,
    40→		public readonly scriptKind: ScriptKind | undefined,
    41→	) { }
    42→}
    43→
    44→class OpenOperation {
    45→	readonly type = BufferOperationType.Open;
    46→	constructor(
    47→		public readonly args: Proto.OpenRequestArgs,
    48→		public readonly scriptKind: ScriptKind | undefined,
    49→	) { }
    50→}
    51→
    52→class ChangeOperation {
    53→	readonly type = BufferOperationType.Change;
    54→	constructor(
    55→		public readonly args: Proto.FileCodeEdits
    56→	) { }
    57→}
    58→
    59→type BufferOperation = CloseOperation | OpenOperation | ChangeOperation;
    60→
    61→/**
    62→ * Manages synchronization of buffers with the TS server.
    63→ *
    64→ * If supported, batches together file changes. This allows the TS server to more efficiently process changes.
    65→ */
    66→class BufferSynchronizer {
    67→
    68→	private readonly _pending: ResourceMap<BufferOperation>;
    69→
    70→	constructor(
    71→		private readonly client: ITypeScriptServiceClient,
    72→		pathNormalizer: (path: vscode.Uri) => string | undefined,
    73→		onCaseInsensitiveFileSystem: boolean
