   135→	private updatePending(resource: vscode.Uri, op: BufferOperation): boolean {
   136→		switch (op.type) {
   137→			case BufferOperationType.Close: {
   138→				const existing = this._pending.get(resource);
   139→				switch (existing?.type) {
   140→					case BufferOperationType.Open:
   141→						if (existing.scriptKind === op.scriptKind) {
   142→							this._pending.delete(resource);
   143→							return false; // Open then close. No need to do anything
