   358→	private readonly _onDidChange = this._register(new vscode.EventEmitter<{
   359→		readonly closed: Iterable<vscode.Uri>;
   360→		readonly opened: Iterable<vscode.Uri>;
   361→	}>());
   362→	public readonly onDidChange = this._onDidChange.event;
   363→
   364→	private readonly _tabResources: ResourceMap<{ readonly tabs: Set<vscode.Tab> }>;
   365→
   366→	constructor(
   367→		normalizePath: (resource: vscode.Uri) => string | undefined,
   368→		config: {
   369→			readonly onCaseInsensitiveFileSystem: boolean;
   370→		},
   371→	) {
   372→		super();
   373→
   374→		this._tabResources = new ResourceMap<{ readonly tabs: Set<vscode.Tab> }>(normalizePath, config);
   375→
   376→		for (const tabGroup of vscode.window.tabGroups.all) {
   377→			for (const tab of tabGroup.tabs) {
   378→				this.add(tab);
   379→			}
   380→		}
   381→
   382→		this._register(vscode.window.tabGroups.onDidChangeTabs(e => {
   383→			const closed = e.closed.flatMap(tab => this.delete(tab));
   384→			const opened = e.opened.flatMap(tab => this.add(tab));
   385→			if (closed.length || opened.length) {
   386→				this._onDidChange.fire({ closed, opened });
   387→			}
   388→		}));
   389→	}
   390→
   391→	public has(resource: vscode.Uri): boolean {
   392→		if (resource.scheme === fileSchemes.vscodeNotebookCell) {
   393→			const notebook = vscode.workspace.notebookDocuments.find(doc =>
   394→				doc.getCells().some(cell => cell.document.uri.toString() === resource.toString()));
   395→
   396→			return !!notebook && this.has(notebook.uri);
   397→		}
   398→
   399→		const entry = this._tabResources.get(resource);
   400→		return !!entry && entry.tabs.size > 0;
   401→	}
   402→
   403→	private add(tab: vscode.Tab): vscode.Uri[] {
   404→		const addedResources: vscode.Uri[] = [];
   405→		for (const uri of this.getResourcesForTab(tab)) {
   406→			const entry = this._tabResources.get(uri);
   407→			if (entry) {
   408→				entry.tabs.add(tab);
   409→			} else {
   410→				this._tabResources.set(uri, { tabs: new Set([tab]) });
   411→				addedResources.push(uri);
   412→			}
   413→		}
   414→		return addedResources;
   415→	}
   416→
   417→	private delete(tab: vscode.Tab): vscode.Uri[] {
   418→		const closedResources: vscode.Uri[] = [];
   419→		for (const uri of this.getResourcesForTab(tab)) {
   420→			const entry = this._tabResources.get(uri);
   421→			if (!entry) {
   422→				continue;
   423→			}
   424→
   425→			entry.tabs.delete(tab);
   426→			if (entry.tabs.size === 0) {
   427→				this._tabResources.delete(uri);
   428→				closedResources.push(uri);
   429→			}
   430→		}
   431→		return closedResources;
   432→	}
   433→
   434→	private getResourcesForTab(tab: vscode.Tab): vscode.Uri[] {
   435→		if (tab.input instanceof vscode.TabInputText) {
   436→			return [tab.input.uri];
   437→		} else if (tab.input instanceof vscode.TabInputTextDiff) {
   438→			return [tab.input.original, tab.input.modified];
   439→		} else if (tab.input instanceof vscode.TabInputNotebook) {
   440→			return [tab.input.uri];
   441→		} else {
   442→			return [];
   443→		}
   444→	}
   445→}
   446→
   447→
   448→export default class BufferSyncSupport extends Disposable {
   449→
   450→	private readonly client: ITypeScriptServiceClient;
   451→
   452→	private _validateJavaScript = true;
   453→	private _validateTypeScript = true;
   454→
   455→	private readonly modeIds: Set<string>;
   456→	private readonly syncedBuffers: SyncedBufferMap;
   457→	private readonly pendingDiagnostics: PendingDiagnostics;
   458→	private readonly diagnosticDelayer: Delayer<any>;
   459→	private pendingGetErr: GetErrRequest | undefined;
   460→	private listening: boolean = false;
   461→	private readonly synchronizer: BufferSynchronizer;
   462→
   463→	private readonly _tabResources: TabResourceTracker;
   464→
   465→	constructor(
   466→		client: ITypeScriptServiceClient,
   467→		modeIds: readonly string[],
   468→		onCaseInsensitiveFileSystem: boolean
   469→	) {
   470→		super();
   471→		this.client = client;
   472→		this.modeIds = new Set<string>(modeIds);
   473→
   474→		this.diagnosticDelayer = new Delayer<any>(300);
   475→
   476→		const pathNormalizer = (path: vscode.Uri) => this.client.toTsFilePath(path);
   477→		this.syncedBuffers = new SyncedBufferMap(pathNormalizer, { onCaseInsensitiveFileSystem });
   478→		this.pendingDiagnostics = new PendingDiagnostics(pathNormalizer, { onCaseInsensitiveFileSystem });
   479→		this.synchronizer = new BufferSynchronizer(client, pathNormalizer, onCaseInsensitiveFileSystem);
   480→
   481→		this._tabResources = this._register(new TabResourceTracker(pathNormalizer, { onCaseInsensitiveFileSystem }));
   482→		this._register(this._tabResources.onDidChange(e => {
   483→			if (this.client.configuration.enableProjectDiagnostics) {
   484→				return;
   485→			}
   486→
   487→			for (const closed of e.closed) {
   488→				const syncedBuffer = this.syncedBuffers.get(closed);
   489→				if (syncedBuffer) {
   490→					this.pendingDiagnostics.delete(closed);
   491→					this.pendingGetErr?.files.delete(closed);
   492→				}
   493→			}
   494→
   495→			for (const opened of e.opened) {
   496→				const syncedBuffer = this.syncedBuffers.get(opened);
   497→				if (syncedBuffer) {
   498→					this.requestDiagnostic(syncedBuffer);
   499→				}
   500→			}
   501→		}));
   502→
   503→		this.updateConfiguration();
   504→		vscode.workspace.onDidChangeConfiguration(this.updateConfiguration, this, this._disposables);
   505→	}
   506→
   507→	private readonly _onDelete = this._register(new vscode.EventEmitter<vscode.Uri>());
   508→	public readonly onDelete = this._onDelete.event;
   509→
   510→	private readonly _onWillChange = this._register(new vscode.EventEmitter<vscode.Uri>());
   511→	public readonly onWillChange = this._onWillChange.event;
   512→
   513→	public listen(): void {
   514→		if (this.listening) {
   515→			return;
   516→		}
   517→		this.listening = true;
   518→		vscode.workspace.onDidOpenTextDocument(this.openTextDocument, this, this._disposables);
   519→		vscode.workspace.onDidCloseTextDocument(this.onDidCloseTextDocument, this, this._disposables);
   520→		vscode.workspace.onDidChangeTextDocument(this.onDidChangeTextDocument, this, this._disposables);
   521→		vscode.window.onDidChangeVisibleTextEditors(e => {
   522→			for (const { document } of e) {
   523→				const syncedBuffer = this.syncedBuffers.get(document.uri);
   524→				if (syncedBuffer) {
   525→					this.requestDiagnostic(syncedBuffer);
   526→				}
   527→			}
   528→		}, this, this._disposables);
   529→		vscode.workspace.textDocuments.forEach(this.openTextDocument, this);
   530→	}
   531→
   532→	public handles(resource: vscode.Uri): boolean {
   533→		return this.syncedBuffers.has(resource);
   534→	}
   535→
   536→	public ensureHasBuffer(resource: vscode.Uri): boolean {
   537→		if (this.syncedBuffers.has(resource)) {
   538→			return true;
   539→		}
   540→
   541→		const existingDocument = vscode.workspace.textDocuments.find(doc => doc.uri.toString() === resource.toString());
   542→		if (existingDocument) {
   543→			return this.openTextDocument(existingDocument);
   544→		}
   545→
   546→		return false;
   547→	}
   548→
   549→	public toVsCodeResource(resource: vscode.Uri): vscode.Uri {
   550→		const filepath = this.client.toTsFilePath(resource);
   551→		for (const buffer of this.syncedBuffers.allBuffers) {
   552→			if (buffer.filepath === filepath) {
   553→				return buffer.resource;
   554→			}
   555→		}
   556→		return resource;
   557→	}
   558→
   559→	public toResource(filePath: string): vscode.Uri {
   560→		const buffer = this.syncedBuffers.getForPath(filePath);
   561→		if (buffer) {
   562→			return buffer.resource;
   563→		}
   564→		return vscode.Uri.file(filePath);
   565→	}
   566→
   567→	public reset(): void {
   568→		this.pendingGetErr?.cancel();
   569→		this.pendingDiagnostics.clear();
   570→		this.synchronizer.reset();
   571→	}
   572→
   573→	public reinitialize(): void {
   574→		this.reset();
   575→		for (const buffer of this.syncedBuffers.allBuffers) {
   576→			buffer.open();
   577→		}
   578→	}
   579→
   580→	public openTextDocument(document: vscode.TextDocument): boolean {
   581→		if (!this.modeIds.has(document.languageId)) {
   582→			return false;
   583→		}
   584→		const resource = document.uri;
   585→		const filepath = this.client.toTsFilePath(resource);
   586→		if (!filepath) {
   587→			return false;
   588→		}
   589→
   590→		if (this.syncedBuffers.has(resource)) {
   591→			return true;
   592→		}
   593→
   594→		const syncedBuffer = new SyncedBuffer(document, filepath, this.client, this.synchronizer);
   595→		this.syncedBuffers.set(resource, syncedBuffer);
   596→		syncedBuffer.open();
   597→		this.requestDiagnostic(syncedBuffer);
   598→		return true;
   599→	}
   600→
   601→	public closeResource(resource: vscode.Uri): void {
   602→		const syncedBuffer = this.syncedBuffers.get(resource);
   603→		if (!syncedBuffer) {
   604→			return;
   605→		}
   606→
   607→		this.pendingDiagnostics.delete(resource);
   608→		this.pendingGetErr?.files.delete(resource);
   609→		this.syncedBuffers.delete(resource);
   610→		const wasBufferOpen = syncedBuffer.close();
   611→		this._onDelete.fire(resource);
   612→		if (wasBufferOpen) {
   613→			this.requestAllDiagnostics();
   614→		}
   615→	}
   616→
   617→	public interruptGetErr<R>(f: () => R): R {
   618→		if (!this.pendingGetErr
   619→			|| this.client.configuration.enableProjectDiagnostics // `geterr` happens on separate server so no need to cancel it.
   620→		) {
   621→			return f();
   622→		}
   623→
   624→		this.pendingGetErr.cancel();
   625→		this.pendingGetErr = undefined;
   626→		const result = f();
   627→		this.triggerDiagnostics();
   628→		return result;
   629→	}
   630→
   631→	public beforeCommand(command: string): void {
   632→		this.synchronizer.beforeCommand(command);
   633→	}
   634→
   635→	public lineCount(resource: vscode.Uri): number | undefined {
   636→		return this.syncedBuffers.get(resource)?.lineCount;
   637→	}
   638→
   639→	private onDidCloseTextDocument(document: vscode.TextDocument): void {
   640→		this.closeResource(document.uri);
   641→	}
   642→
   643→	private onDidChangeTextDocument(e: vscode.TextDocumentChangeEvent): void {
   644→		const syncedBuffer = this.syncedBuffers.get(e.document.uri);
   645→		if (!syncedBuffer) {
   646→			return;
   647→		}
   648→
   649→		this._onWillChange.fire(syncedBuffer.resource);
   650→
   651→		syncedBuffer.onContentChanged(e.contentChanges);
   652→		const didTrigger = this.requestDiagnostic(syncedBuffer);
   653→
   654→		if (!didTrigger && this.pendingGetErr) {
   655→			// In this case we always want to re-trigger all diagnostics
   656→			this.pendingGetErr.cancel();
   657→			this.pendingGetErr = undefined;
   658→			this.triggerDiagnostics();
   659→		}
   660→	}
   661→
   662→	public requestAllDiagnostics() {
   663→		for (const buffer of this.syncedBuffers.allBuffers) {
   664→			if (this.shouldValidate(buffer)) {
   665→				this.pendingDiagnostics.set(buffer.resource, Date.now());
   666→			}
   667→		}
   668→		this.triggerDiagnostics();
   669→	}
   670→
   671→	public getErr(resources: readonly vscode.Uri[]): any {
   672→		const handledResources = resources.filter(resource => this.handles(resource));
   673→		if (!handledResources.length) {
   674→			return;
   675→		}
   676→
   677→		for (const resource of handledResources) {
   678→			this.pendingDiagnostics.set(resource, Date.now());
   679→		}
   680→
   681→		this.triggerDiagnostics();
   682→	}
   683→
   684→	private triggerDiagnostics(delay: number = 200) {
   685→		this.diagnosticDelayer.trigger(() => {
   686→			this.sendPendingDiagnostics();
   687→		}, delay);
   688→	}
   689→
   690→	private requestDiagnostic(buffer: SyncedBuffer): boolean {
   691→		if (!this.shouldValidate(buffer)) {
   692→			return false;
   693→		}
   694→
   695→		this.pendingDiagnostics.set(buffer.resource, Date.now());
   696→
   697→		const delay = Math.min(Math.max(Math.ceil(buffer.lineCount / 20), 300), 800);
   698→		this.triggerDiagnostics(delay);
   699→		return true;
   700→	}
   701→
   702→	public hasPendingDiagnostics(resource: vscode.Uri): boolean {
   703→		return this.pendingDiagnostics.has(resource);
   704→	}
   705→
   706→	private sendPendingDiagnostics(): void {
   707→		const orderedFileSet = this.pendingDiagnostics.getOrderedFileSet();
   708→
   709→		if (this.pendingGetErr) {
   710→			this.pendingGetErr.cancel();
   711→
   712→			for (const { resource } of this.pendingGetErr.files.entries()) {
   713→				if (this.syncedBuffers.get(resource)) {
   714→					orderedFileSet.set(resource, undefined);
   715→				}
   716→			}
   717→
   718→			this.pendingGetErr = undefined;
   719→		}
   720→
   721→		// Add all open TS buffers to the geterr request. They might be visible
   722→		for (const buffer of this.syncedBuffers.values()) {
   723→			const editors = vscode.window.visibleTextEditors.filter(editor => editor.document.uri.toString() === buffer.resource.toString());
   724→			const visibleRanges = editors.flatMap(editor => editor.visibleRanges);
   725→			orderedFileSet.set(buffer.resource, visibleRanges.length ? visibleRanges : undefined);
   726→		}
   727→
   728→		for (const { resource } of orderedFileSet.entries()) {
   729→			const buffer = this.syncedBuffers.get(resource);
   730→			if (buffer && !this.shouldValidate(buffer)) {
   731→				orderedFileSet.delete(resource);
   732→			}
   733→		}
   734→
   735→		if (orderedFileSet.size) {
   736→			const getErr = this.pendingGetErr = GetErrRequest.executeGetErrRequest(this.client, orderedFileSet, () => {
   737→				if (this.pendingGetErr === getErr) {
   738→					this.pendingGetErr = undefined;
   739→				}
   740→			});
   741→		}
   742→
   743→		this.pendingDiagnostics.clear();
   744→	}
   745→
   746→	private updateConfiguration() {
   747→		const jsConfig = vscode.workspace.getConfiguration('javascript', null);
   748→		const tsConfig = vscode.workspace.getConfiguration('typescript', null);
   749→
   750→		this._validateJavaScript = jsConfig.get<boolean>('validate.enable', true);
   751→		this._validateTypeScript = tsConfig.get<boolean>('validate.enable', true);
   752→	}
   753→
   754→	private shouldValidate(buffer: SyncedBuffer): boolean {
   755→		if (fileSchemes.isOfScheme(buffer.resource, fileSchemes.chatCodeBlock)) {
   756→			return false;
   757→		}
   758→
   759→		if (!this.client.configuration.enableProjectDiagnostics && !this._tabResources.has(buffer.resource)) { // Only validate resources that are showing to the user
   760→			return false;
   761→		}
   762→
   763→		switch (buffer.languageId) {
   764→			case languageModeIds.javascript:
   765→			case languageModeIds.javascriptreact:
   766→				return this._validateJavaScript;
   767→
   768→			case languageModeIds.typescript:
   769→			case languageModeIds.typescriptreact:
   770→			default:
   771→				return this._validateTypeScript;
   772→		}
   773→	}
   774→}
