   247→class PendingDiagnostics extends ResourceMap<number> {
   248→	public getOrderedFileSet(): ResourceMap<void | vscode.Range[]> {
   249→		const orderedResources = Array.from(this.entries())
   250→			.sort((a, b) => a.value - b.value)
   251→			.map(entry => entry.resource);
   252→
   253→		const map = new ResourceMap<void | vscode.Range[]>(this._normalizePath, this.config);
   254→		for (const resource of orderedResources) {
   255→			map.set(resource, undefined);
   256→		}
   257→		return map;
   258→	}
   259→}
   260→
   261→class GetErrRequest {
   262→
   263→	public static executeGetErrRequest(
   264→		client: ITypeScriptServiceClient,
   265→		files: ResourceMap<void | vscode.Range[]>,
   266→		onDone: () => void
   267→	) {
   268→		return new GetErrRequest(client, files, onDone);
   269→	}
   270→
   271→	private _done: boolean = false;
   272→	private readonly _token: vscode.CancellationTokenSource = new vscode.CancellationTokenSource();
   273→
   274→	private constructor(
   275→		private readonly client: ITypeScriptServiceClient,
   276→		public readonly files: ResourceMap<void | vscode.Range[]>,
   277→		onDone: () => void
   278→	) {
   279→		if (!this.isErrorReportingEnabled()) {
   280→			this._done = true;
   281→			setImmediate(onDone);
   282→			return;
   283→		}
   284→
   285→		const supportsSyntaxGetErr = this.client.apiVersion.gte(API.v440);
   286→		const fileEntries = Array.from(files.entries()).filter(entry => supportsSyntaxGetErr || client.hasCapabilityForResource(entry.resource, ClientCapability.Semantic));
   287→		const allFiles = coalesce(fileEntries
   288→			.map(entry => client.toTsFilePath(entry.resource)));
   289→
   290→		if (!allFiles.length) {
   291→			this._done = true;
   292→			setImmediate(onDone);
   293→		} else {
   294→			let request;
   295→			if (this.areProjectDiagnosticsEnabled()) {
   296→				// Note that geterrForProject is almost certainly not the api we want here as it ends up computing far
   297→				// too many diagnostics
   298→				request = client.executeAsync('geterrForProject', { delay: 0, file: allFiles[0] }, this._token.token);
   299→			}
   300→			else {
   301→				let requestFiles;
   302→				if (this.areRegionDiagnosticsEnabled()) {
   303→					requestFiles = coalesce(fileEntries
   304→						.map(entry => {
   305→							const file = client.toTsFilePath(entry.resource);
   306→							const ranges = entry.value;
   307→							if (file && ranges) {
   308→								return typeConverters.Range.toFileRangesRequestArgs(file, ranges);
   309→							}
   310→
   311→							return file;
   312→						}));
   313→				}
   314→				else {
   315→					requestFiles = allFiles;
   316→				}
   317→				request = client.executeAsync('geterr', { delay: 0, files: requestFiles }, this._token.token);
   318→			}
   319→
   320→			request.finally(() => {
   321→				if (this._done) {
   322→					return;
   323→				}
   324→				this._done = true;
   325→				onDone();
   326→			});
   327→		}
   328→	}
   329→
   330→	private isErrorReportingEnabled() {
   331→		if (this.client.apiVersion.gte(API.v440)) {
   332→			return true;
   333→		} else {
   334→			// Older TS versions only support `getErr` on semantic server
   335→			return this.client.capabilities.has(ClientCapability.Semantic);
   336→		}
   337→	}
   338→
   339→	private areProjectDiagnosticsEnabled() {
   340→		return this.client.configuration.enableProjectDiagnostics && this.client.capabilities.has(ClientCapability.Semantic);
   341→	}
   342→
   343→	private areRegionDiagnosticsEnabled() {
   344→		return this.client.configuration.enableRegionDiagnostics && this.client.apiVersion.gte(API.v560);
   345→	}
   346→
   347→	public cancel(): any {
   348→		if (!this._done) {
   349→			this._token.cancel();
   350→		}
   351→
   352→		this._token.dispose();
   353→	}
   354→}
   355→
   356→class TabResourceTracker extends Disposable {
   357→
   358→	private readonly _onDidChange = this._register(new vscode.EventEmitter<{
   359→		readonly closed: Iterable<vscode.Uri>;
   360→		readonly opened: Iterable<vscode.Uri>;
   361→	}>());
   362→	public readonly onDidChange = this._onDidChange.event;
   363→
   364→	private readonly _tabResources: ResourceMap<{ readonly tabs: Set<vscode.Tab> }>;
   365→
   366→	constructor(
   367→		normalizePath: (resource: vscode.Uri) => string | undefined,
   368→		config: {
   369→			readonly onCaseInsensitiveFileSystem: boolean;
   370→		},
   371→	) {
   372→		super();
   373→
   374→		this._tabResources = new ResourceMap<{ readonly tabs: Set<vscode.Tab> }>(normalizePath, config);
   375→
   376→		for (const tabGroup of vscode.window.tabGroups.all) {
   377→			for (const tab of tabGroup.tabs) {
   378→				this.add(tab);
   379→			}
   380→		}
   381→
   382→		this._register(vscode.window.tabGroups.onDidChangeTabs(e => {
   383→			const closed = e.closed.flatMap(tab => this.delete(tab));
   384→			const opened = e.opened.flatMap(tab => this.add(tab));
   385→			if (closed.length || opened.length) {
   386→				this._onDidChange.fire({ closed, opened });
   387→			}
   388→		}));
   389→	}
   390→
   391→	public has(resource: vscode.Uri): boolean {
   392→		if (resource.scheme === fileSchemes.vscodeNotebookCell) {
   393→			const notebook = vscode.workspace.notebookDocuments.find(doc =>
   394→				doc.getCells().some(cell => cell.document.uri.toString() === resource.toString()));
   395→
   396→			return !!notebook && this.has(notebook.uri);
   397→		}
   398→
   399→		const entry = this._tabResources.get(resource);
   400→		return !!entry && entry.tabs.size > 0;
   401→	}
   402→
   403→	private add(tab: vscode.Tab): vscode.Uri[] {
   404→		const addedResources: vscode.Uri[] = [];
   405→		for (const uri of this.getResourcesForTab(tab)) {
   406→			const entry = this._tabResources.get(uri);
   407→			if (entry) {
   408→				entry.tabs.add(tab);
   409→			} else {
   410→				this._tabResources.set(uri, { tabs: new Set([tab]) });
   411→				addedResources.push(uri);
   412→			}
   413→		}
   414→		return addedResources;
   415→	}
   416→
   417→	private delete(tab: vscode.Tab): vscode.Uri[] {
   418→		const closedResources: vscode.Uri[] = [];
   419→		for (const uri of this.getResourcesForTab(tab)) {
   420→			const entry = this._tabResources.get(uri);
   421→			if (!entry) {
   422→				continue;
   423→			}
   424→
   425→			entry.tabs.delete(tab);
   426→			if (entry.tabs.size === 0) {
   427→				this._tabResources.delete(uri);
   428→				closedResources.push(uri);
   429→			}
   430→		}
   431→		return closedResources;
   432→	}
   433→
   434→	private getResourcesForTab(tab: vscode.Tab): vscode.Uri[] {
   435→		if (tab.input instanceof vscode.TabInputText) {
   436→			return [tab.input.uri];
   437→		} else if (tab.input instanceof vscode.TabInputTextDiff) {
   438→			return [tab.input.original, tab.input.modified];
   439→		} else if (tab.input instanceof vscode.TabInputNotebook) {
   440→			return [tab.input.uri];
   441→		} else {
   442→			return [];
   443→		}
   444→	}
   445→}
