    71→		private readonly client: ITypeScriptServiceClient,
    72→		pathNormalizer: (path: vscode.Uri) => string | undefined,
    73→		onCaseInsensitiveFileSystem: boolean
    74→	) {
    75→		this._pending = new ResourceMap<BufferOperation>(pathNormalizer, {
    76→			onCaseInsensitiveFileSystem
    77→		});
    78→	}
    79→
    80→	public open(resource: vscode.Uri, args: Proto.OpenRequestArgs) {
    81→		this.updatePending(resource, new OpenOperation(args, args.scriptKindName));
    82→	}
    83→
    84→	/**
    85→	 * @return Was the buffer open?
    86→	 */
    87→	public close(resource: vscode.Uri, filepath: string, scriptKind: ScriptKind | undefined): boolean {
    88→		return this.updatePending(resource, new CloseOperation(filepath, scriptKind));
    89→	}
    90→
    91→	public change(resource: vscode.Uri, filepath: string, events: readonly vscode.TextDocumentContentChangeEvent[]) {
    92→		if (!events.length) {
    93→			return;
    94→		}
    95→
    96→		this.updatePending(resource, new ChangeOperation({
    97→			fileName: filepath,
    98→			textChanges: events.map((change): Proto.CodeEdit => ({
    99→				newText: change.text,
   100→				start: typeConverters.Position.toLocation(change.range.start),
   101→				end: typeConverters.Position.toLocation(change.range.end),
   102→			})).reverse(), // Send the edits end-of-document to start-of-document order
   103→		}));
   104→	}
   105→
   106→	public reset(): void {
   107→		this._pending.clear();
   108→	}
   109→
   110→	public beforeCommand(command: string): void {
   111→		if (command === 'updateOpen') {
   112→			return;
   113→		}
   114→
   115→		this.flush();
   116→	}
   117→
   118→	private flush() {
   119→		if (this._pending.size > 0) {
   120→			const closedFiles: string[] = [];
   121→			const openFiles: Proto.OpenRequestArgs[] = [];
   122→			const changedFiles: Proto.FileCodeEdits[] = [];
   123→			for (const change of this._pending.values()) {
   124→				switch (change.type) {
   125→					case BufferOperationType.Change: changedFiles.push(change.args); break;
   126→					case BufferOperationType.Open: openFiles.push(change.args); break;
   127→					case BufferOperationType.Close: closedFiles.push(change.args); break;
   128→				}
   129→			}
   130→			this.client.execute('updateOpen', { changedFiles, closedFiles, openFiles }, nulToken, { nonRecoverable: true });
   131→			this._pending.clear();
   132→		}
   133→	}
   134→
   135→	private updatePending(resource: vscode.Uri, op: BufferOperation): boolean {
   136→		switch (op.type) {
   137→			case BufferOperationType.Close: {
   138→				const existing = this._pending.get(resource);
   139→				switch (existing?.type) {
   140→					case BufferOperationType.Open:
   141→						if (existing.scriptKind === op.scriptKind) {
   142→							this._pending.delete(resource);
   143→							return false; // Open then close. No need to do anything
   144→						}
   145→				}
   146→				break;
   147→			}
   148→		}
   149→
   150→		if (this._pending.has(resource)) {
   151→			// we saw this file before, make sure we flush before working with it again
   152→			this.flush();
   153→		}
   154→		this._pending.set(resource, op);
   155→		return true;
   156→	}
   157→}
