   448→export default class BufferSyncSupport extends Disposable {
   449→
   450→	private readonly client: ITypeScriptServiceClient;
   451→
   452→	private _validateJavaScript = true;
   453→	private _validateTypeScript = true;
   454→
   455→	private readonly modeIds: Set<string>;
   456→	private readonly syncedBuffers: SyncedBufferMap;
   457→	private readonly pendingDiagnostics: PendingDiagnostics;
   458→	private readonly diagnosticDelayer: Delayer<any>;
   459→	private pendingGetErr: GetErrRequest | undefined;
   460→	private listening: boolean = false;
   461→	private readonly synchronizer: BufferSynchronizer;
   462→
   463→	private readonly _tabResources: TabResourceTracker;
   464→
   465→	constructor(
   466→		client: ITypeScriptServiceClient,
   467→		modeIds: readonly string[],
   468→		onCaseInsensitiveFileSystem: boolean
   469→	) {
   470→		super();
   471→		this.client = client;
   472→		this.modeIds = new Set<string>(modeIds);
   473→
   474→		this.diagnosticDelayer = new Delayer<any>(300);
   475→
   476→		const pathNormalizer = (path: vscode.Uri) => this.client.toTsFilePath(path);
   477→		this.syncedBuffers = new SyncedBufferMap(pathNormalizer, { onCaseInsensitiveFileSystem });
   478→		this.pendingDiagnostics = new PendingDiagnostics(pathNormalizer, { onCaseInsensitiveFileSystem });
   479→		this.synchronizer = new BufferSynchronizer(client, pathNormalizer, onCaseInsensitiveFileSystem);
   480→
   481→		this._tabResources = this._register(new TabResourceTracker(pathNormalizer, { onCaseInsensitiveFileSystem }));
   482→		this._register(this._tabResources.onDidChange(e => {
   483→			if (this.client.configuration.enableProjectDiagnostics) {
   484→				return;
   485→			}
   486→
   487→			for (const closed of e.closed) {
   488→				const syncedBuffer = this.syncedBuffers.get(closed);
   489→				if (syncedBuffer) {
   490→					this.pendingDiagnostics.delete(closed);
   491→					this.pendingGetErr?.files.delete(closed);
   492→				}
   493→			}
   494→
   495→			for (const opened of e.opened) {
   496→				const syncedBuffer = this.syncedBuffers.get(opened);
   497→				if (syncedBuffer) {
   498→					this.requestDiagnostic(syncedBuffer);
   499→				}
   500→			}
   501→		}));
   502→
   503→		this.updateConfiguration();
   504→		vscode.workspace.onDidChangeConfiguration(this.updateConfiguration, this, this._disposables);
   505→	}
   506→
   507→	private readonly _onDelete = this._register(new vscode.EventEmitter<vscode.Uri>());
   508→	public readonly onDelete = this._onDelete.event;
   509→
   510→	private readonly _onWillChange = this._register(new vscode.EventEmitter<vscode.Uri>());
   511→	public readonly onWillChange = this._onWillChange.event;
   512→
   513→	public listen(): void {
   514→		if (this.listening) {
   515→			return;
   516→		}
   517→		this.listening = true;
   518→		vscode.workspace.onDidOpenTextDocument(this.openTextDocument, this, this._disposables);
   519→		vscode.workspace.onDidCloseTextDocument(this.onDidCloseTextDocument, this, this._disposables);
   520→		vscode.workspace.onDidChangeTextDocument(this.onDidChangeTextDocument, this, this._disposables);
   521→		vscode.window.onDidChangeVisibleTextEditors(e => {
   522→			for (const { document } of e) {
   523→				const syncedBuffer = this.syncedBuffers.get(document.uri);
   524→				if (syncedBuffer) {
   525→					this.requestDiagnostic(syncedBuffer);
   526→				}
   527→			}
   528→		}, this, this._disposables);
   529→		vscode.workspace.textDocuments.forEach(this.openTextDocument, this);
   530→
   531→		// Watch for file system changes (e.g. from git branch switches) to clear stale diagnostics
   532→		this.setupFileSystemWatcher();
   533→	}
   534→
   535→	private setupFileSystemWatcher(): void {
   536→		// Create a file system watcher for TypeScript/JavaScript files
   537→		const watcher = this._register(vscode.workspace.createFileSystemWatcher('**/*.{ts,tsx,js,jsx}'));
   538→
   539→		// When files change on disk, clear stale diagnostics
   540→		watcher.onDidChange((uri) => {
   541→			this.onFileSystemChange(uri);
   542→		}, this, this._disposables);
   543→
   544→		watcher.onDidDelete((uri) => {
   545→			this.onFileSystemDelete(uri);
   546→		}, this, this._disposables);
   547→	}
   548→
   549→	private onFileSystemChange(uri: vscode.Uri): void {
   550→		// Clear stale diagnostics for files that changed on disk
   551→		// This handles cases where git operations modify files without VS Code text document changes
   552→		this.client.diagnosticsManager.deleteAllDiagnosticsInFile(uri);
   553→
   554→		// If this file is open in the editor, trigger re-diagnostics
   555→		if (this.syncedBuffers.has(uri)) {
   556→			const buffer = this.syncedBuffers.get(uri);
   557→			if (buffer) {
   558→				this.requestDiagnostic(buffer);
   559→			}
   560→		}
   561→	}
   562→
   563→	private onFileSystemDelete(uri: vscode.Uri): void {
   564→		// Clear diagnostics for deleted files
   565→		this.client.diagnosticsManager.deleteAllDiagnosticsInFile(uri);
   566→	}
   567→
   568→	public handles(resource: vscode.Uri): boolean {
   569→		return this.syncedBuffers.has(resource);
   570→	}
   571→
   572→	public ensureHasBuffer(resource: vscode.Uri): boolean {
   573→		if (this.syncedBuffers.has(resource)) {
   574→			return true;
   575→		}
   576→
   577→		const existingDocument = vscode.workspace.textDocuments.find(doc => doc.uri.toString() === resource.toString());
   578→		if (existingDocument) {
   579→			return this.openTextDocument(existingDocument);
   580→		}
   581→
   582→		return false;
   583→	}
   584→
   585→	public toVsCodeResource(resource: vscode.Uri): vscode.Uri {
   586→		const filepath = this.client.toTsFilePath(resource);
   587→		for (const buffer of this.syncedBuffers.allBuffers) {
   588→			if (buffer.filepath === filepath) {
   589→				return buffer.resource;
   590→			}
   591→		}
   592→		return resource;
   593→	}
   594→
   595→	public toResource(filePath: string): vscode.Uri {
   596→		const buffer = this.syncedBuffers.getForPath(filePath);
   597→		if (buffer) {
   598→			return buffer.resource;
   599→		}
   600→		return vscode.Uri.file(filePath);
   601→	}
   602→
   603→	public reset(): void {
   604→		this.pendingGetErr?.cancel();
   605→		this.pendingDiagnostics.clear();
   606→		this.synchronizer.reset();
   607→	}
   608→
   609→	public reinitialize(): void {
   610→		this.reset();
   611→		for (const buffer of this.syncedBuffers.allBuffers) {
   612→			buffer.open();
   613→		}
   614→	}
   615→
   616→	public openTextDocument(document: vscode.TextDocument): boolean {
   617→		if (!this.modeIds.has(document.languageId)) {
   618→			return false;
   619→		}
   620→		const resource = document.uri;
   621→		const filepath = this.client.toTsFilePath(resource);
   622→		if (!filepath) {
   623→			return false;
   624→		}
   625→
   626→		if (this.syncedBuffers.has(resource)) {
   627→			return true;
   628→		}
   629→
   630→		const syncedBuffer = new SyncedBuffer(document, filepath, this.client, this.synchronizer);
   631→		this.syncedBuffers.set(resource, syncedBuffer);
   632→		syncedBuffer.open();
   633→		this.requestDiagnostic(syncedBuffer);
   634→		return true;
   635→	}
   636→
   637→	public closeResource(resource: vscode.Uri): void {
   638→		const syncedBuffer = this.syncedBuffers.get(resource);
   639→		if (!syncedBuffer) {
   640→			return;
   641→		}
   642→
   643→		this.pendingDiagnostics.delete(resource);
   644→		this.pendingGetErr?.files.delete(resource);
   645→		this.syncedBuffers.delete(resource);
   646→		const wasBufferOpen = syncedBuffer.close();
   647→		this._onDelete.fire(resource);
   648→		if (wasBufferOpen) {
   649→			this.requestAllDiagnostics();
   650→		}
   651→	}
   652→
