   634→		return true;
   635→	}
   636→
   637→	public closeResource(resource: vscode.Uri): void {
   638→		const syncedBuffer = this.syncedBuffers.get(resource);
   639→		if (!syncedBuffer) {
   640→			return;
   641→		}
   642→
   643→		this.pendingDiagnostics.delete(resource);
   644→		this.pendingGetErr?.files.delete(resource);
   645→		this.syncedBuffers.delete(resource);
   646→		const wasBufferOpen = syncedBuffer.close();
   647→		this._onDelete.fire(resource);
   648→		if (wasBufferOpen) {
