   653→	public interruptGetErr<R>(f: () => R): R {
   654→		if (!this.pendingGetErr
   655→			|| this.client.configuration.enableProjectDiagnostics // `geterr` happens on separate server so no need to cancel it.
   656→		) {
   657→			return f();
   658→		}
   659→
   660→		this.pendingGetErr.cancel();
   661→		this.pendingGetErr = undefined;
   662→		const result = f();
   663→		this.triggerDiagnostics();
   664→		return result;
   665→	}
