   687→		syncedBuffer.onContentChanged(e.contentChanges);
   688→		const didTrigger = this.requestDiagnostic(syncedBuffer);
   689→
   690→		if (!didTrigger && this.pendingGetErr) {
   691→			// In this case we always want to re-trigger all diagnostics
   692→			this.pendingGetErr.cancel();
   693→			this.pendingGetErr = undefined;
   694→			this.triggerDiagnostics();
   695→		}
   696→	}
