   698→	public requestAllDiagnostics() {
   699→		for (const buffer of this.syncedBuffers.allBuffers) {
   700→			if (this.shouldValidate(buffer)) {
   701→				this.pendingDiagnostics.set(buffer.resource, Date.now());
   702→			}
   703→		}
   704→		this.triggerDiagnostics();
   705→	}
   706→
   707→	public getErr(resources: readonly vscode.Uri[]): any {
   708→		const handledResources = resources.filter(resource => this.handles(resource));
   709→		if (!handledResources.length) {
   710→			return;
   711→		}
   712→
   713→		for (const resource of handledResources) {
   714→			this.pendingDiagnostics.set(resource, Date.now());
   715→		}
   716→
   717→		this.triggerDiagnostics();
   718→	}
   719→
   720→	private triggerDiagnostics(delay: number = 200) {
   721→		this.diagnosticDelayer.trigger(() => {
   722→			this.sendPendingDiagnostics();
   723→		}, delay);
   724→	}
   725→
   726→	private requestDiagnostic(buffer: SyncedBuffer): boolean {
   727→		if (!this.shouldValidate(buffer)) {
   728→			return false;
   729→		}
   730→
   731→		this.pendingDiagnostics.set(buffer.resource, Date.now());
   732→
   733→		const delay = Math.min(Math.max(Math.ceil(buffer.lineCount / 20), 300), 800);
   734→		this.triggerDiagnostics(delay);
   735→		return true;
   736→	}
   737→
   738→	public hasPendingDiagnostics(resource: vscode.Uri): boolean {
   739→		return this.pendingDiagnostics.has(resource);
   740→	}
   741→
   742→	private sendPendingDiagnostics(): void {
   743→		const orderedFileSet = this.pendingDiagnostics.getOrderedFileSet();
   744→
   745→		if (this.pendingGetErr) {
   746→			this.pendingGetErr.cancel();
   747→
   748→			for (const { resource } of this.pendingGetErr.files.entries()) {
   749→				if (this.syncedBuffers.get(resource)) {
   750→					orderedFileSet.set(resource, undefined);
   751→				}
   752→			}
   753→
   754→			this.pendingGetErr = undefined;
   755→		}
   756→
   757→		// Add all open TS buffers to the geterr request. They might be visible
   758→		for (const buffer of this.syncedBuffers.values()) {
   759→			const editors = vscode.window.visibleTextEditors.filter(editor => editor.document.uri.toString() === buffer.resource.toString());
   760→			const visibleRanges = editors.flatMap(editor => editor.visibleRanges);
   761→			orderedFileSet.set(buffer.resource, visibleRanges.length ? visibleRanges : undefined);
   762→		}
   763→
   764→		for (const { resource } of orderedFileSet.entries()) {
   765→			const buffer = this.syncedBuffers.get(resource);
   766→			if (buffer && !this.shouldValidate(buffer)) {
   767→				orderedFileSet.delete(resource);
   768→			}
   769→		}
   770→
   771→		if (orderedFileSet.size) {
   772→			const getErr = this.pendingGetErr = GetErrRequest.executeGetErrRequest(this.client, orderedFileSet, () => {
   773→				if (this.pendingGetErr === getErr) {
   774→					this.pendingGetErr = undefined;
   775→				}
   776→			});
   777→		}
   778→
   779→		this.pendingDiagnostics.clear();
   780→	}
