   782→	private updateConfiguration() {
   783→		const jsConfig = vscode.workspace.getConfiguration('javascript', null);
   784→		const tsConfig = vscode.workspace.getConfiguration('typescript', null);
   785→
   786→		this._validateJavaScript = jsConfig.get<boolean>('validate.enable', true);
   787→		this._validateTypeScript = tsConfig.get<boolean>('validate.enable', true);
   788→	}
   789→
   790→	private shouldValidate(buffer: SyncedBuffer): boolean {
   791→		if (fileSchemes.isOfScheme(buffer.resource, fileSchemes.chatCodeBlock)) {
   792→			return false;
   793→		}
   794→
   795→		if (!this.client.configuration.enableProjectDiagnostics && !this._tabResources.has(buffer.resource)) { // Only validate resources that are showing to the user
   796→			return false;
   797→		}
   798→
   799→		switch (buffer.languageId) {
   800→			case languageModeIds.javascript:
   801→			case languageModeIds.javascriptreact:
   802→				return this._validateJavaScript;
   803→
   804→			case languageModeIds.typescript:
   805→			case languageModeIds.typescriptreact:
   806→			default:
   807→				return this._validateTypeScript;
   808→		}
   809→	}
   810→}
